# Mostrar la lista de lenguajes de programación con opciones enumeradas
def mostrar_lenguajes():
    print("\nLista de lenguajes de programación:")
    for i, lenguaje in enumerate(lenguajes_de_programacion, start=1):
        print(f"{i}. {lenguaje}")

# Bucle para permitir al usuario seguir buscando opciones hasta que seleccione una válida
while True:
    mostrar_lenguajes()
    # Pedir al usuario que elija un número de la lista
    opcion = input("\nPor favor, elija un número para ver el lenguaje de programación correspondiente (o 'salir' para salir): ")

    # Verificar si el usuario quiere salir
    if opcion.lower() == "salir":
        print("Saliendo del programa...")
        break

    # Verificar si la opción es válida y mostrar la reseña del lenguaje de programación correspondiente
    try:
        opcion = int(opcion)
        if 1 <= opcion <= len(lenguajes_de_programacion):
            print(f"\nReseña de {lenguajes_de_programacion[opcion - 1]}:\n{reseñas[opcion - 1]}")
        else:
            print("Opción inválida. Por favor, elija un número válido.")
    except ValueError:
        print("Debe ingresar un número válido.")
